const synthetics = require('Synthetics');
const log = require('SyntheticsLogger');

const moodleHealthCheck = async function () {
  // Default URL provided at canary creation time via env var.
  // Use synthetics' built-in HTTP client; it auto-instruments
  // metrics like Duration, SuccessPercent, etc.
  const url = process.env.MOODLE_URL;

  if (!url) {
    throw new Error('MOODLE_URL environment variable is not set');
  }

  log.info(`Checking Moodle availability at ${url}`);

  const requestOptions = {
    hostname: new URL(url).hostname,
    method: 'GET',
    path: new URL(url).pathname + new URL(url).search,
    port: 443,
    protocol: 'https:',
    headers: {
      'User-Agent': [synthetics.getCanaryUserAgentString(), 'MoodleHealthCheck'].join(' ')
    }
  };

  const stepConfig = {
    includeRequestHeaders: false,
    includeResponseHeaders: true,
    restrictedHeaders: [],
    includeRequestBody: false,
    includeResponseBody: false,
    continueOnHttpStepFailure: false
  };

  await synthetics.executeHttpStep(
    'Moodle login page returns 200',
    requestOptions,
    validateResponse,
    stepConfig
  );
};

const validateResponse = async function (res) {
  return new Promise((resolve, reject) => {
    if (res.statusCode < 200 || res.statusCode > 299) {
      reject(`Failed with status ${res.statusCode} ${res.statusMessage}`);
      return;
    }
    res.on('data', () => {});
    res.on('end', () => resolve());
  });
};

exports.handler = async () => {
  return await moodleHealthCheck();
};
